import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import './Auth.css';

export function DangNhap() {
  const [form, setForm] = useState({ email: '', matKhau: '' });
  const { dangNhap, loading, error } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();
    const ok = await dangNhap(form.email, form.matKhau);
    if (ok) { toast.success('Đăng nhập thành công!'); navigate('/'); }
    else toast.error(error || 'Đăng nhập thất bại');
  };

  return (
    <div className="auth-wrapper">
      <div className="auth-card card">
        <div className="card-body">
          <div className="auth-logo">🏠 RoomMate</div>
          <h2 className="auth-title">Đăng nhập</h2>
          <p className="auth-subtitle">Chào mừng bạn trở lại!</p>
          {error && <div className="alert alert-danger">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Email</label>
              <input className="form-control" type="email" required
                value={form.email} onChange={e => setForm({...form, email: e.target.value})}
                placeholder="example@email.com" />
            </div>
            <div className="form-group">
              <label className="form-label">Mật khẩu</label>
              <input className="form-control" type="password" required
                value={form.matKhau} onChange={e => setForm({...form, matKhau: e.target.value})}
                placeholder="••••••••" />
            </div>
            <button className="btn btn-primary btn-block" disabled={loading}>
              {loading ? '⏳ Đang đăng nhập...' : '🔑 Đăng nhập'}
            </button>
          </form>
          <p className="auth-footer">
            Chưa có tài khoản? <Link to="/dang-ky">Đăng ký ngay</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

export default DangNhap;
